export const arkade_kitties = "// ArkadeKitties - Simplified Breeding Contract\n// Demonstrates commit-reveal breeding with oracle randomness\n//\n// Key features demonstrated:\n// - group.isFresh: Detect newly minted kitties\n// - group.control: Verify species membership\n// - group.metadataHash: Verify genome/attributes\n// - group.delta: Detect minting vs transfer\n//\n// Asset hierarchy:\n// - speciesControlId: The \"species\" control asset (e.g., \"ArkadeKitties\")\n// - Each kitty is a unique asset controlled by speciesControlId\n// - Breeding creates a new kitty with isFresh=1\n\noptions {\n    server = server;\n    exit = 576;  // ~4 days for breeding timeout\n}\n\ncontract ArkadeKitties(\n    bytes32 speciesControlId,\n    pubkey oraclePk\n) {\n    // Breed two kitties to create a new one\n    // Parents must be species-controlled, child must be fresh\n    function breed(\n        bytes32 sireId,\n        bytes32 dameId,\n        bytes32 childId,\n        bytes32 sireGenomeHash,\n        bytes32 dameGenomeHash,\n        bytes32 expectedChildMetadataHash,\n        signature oracleSig,\n        int childOutputIdx,\n        int sireOutputIdx,\n        int dameOutputIdx,\n        int ctrlOutputIdx\n    ) {\n        // Verify sire is species-controlled with correct genome\n        let sireGroup = tx.assetGroups.find(sireId);\n        require(sireGroup.control == speciesControlId, \"sire not species-controlled\");\n        require(sireGroup.metadataHash == sireGenomeHash, \"sire genome mismatch\");\n        require(sireGroup.delta == 0, \"sire must be retained\");\n\n        // Verify dame is species-controlled with correct genome\n        let dameGroup = tx.assetGroups.find(dameId);\n        require(dameGroup.control == speciesControlId, \"dame not species-controlled\");\n        require(dameGroup.metadataHash == dameGenomeHash, \"dame genome mismatch\");\n        require(dameGroup.delta == 0, \"dame must be retained\");\n\n        // Verify child is fresh (new issuance in this tx)\n        let childGroup = tx.assetGroups.find(childId);\n        require(childGroup.isFresh == 1, \"child must be fresh\");\n        require(childGroup.delta == 1, \"must mint exactly 1 child\");\n        require(childGroup.control == speciesControlId, \"child not species-controlled\");\n        require(childGroup.metadataHash == expectedChildMetadataHash, \"child genome mismatch\");\n\n        // Species control must be retained (delta == 0)\n        let ctrlGroup = tx.assetGroups.find(speciesControlId);\n        require(ctrlGroup.delta == 0, \"species control must be retained\");\n\n        // Oracle signature validates the breeding (genome combination)\n        require(checkSig(oracleSig, oraclePk), \"invalid oracle sig\");\n\n        // Verify outputs contain all assets\n        require(tx.outputs[childOutputIdx].assets.lookup(childId) == 1, \"child not in output\");\n        require(tx.outputs[sireOutputIdx].assets.lookup(sireId) == 1, \"sire not returned\");\n        require(tx.outputs[dameOutputIdx].assets.lookup(dameId) == 1, \"dame not returned\");\n        require(tx.outputs[ctrlOutputIdx].assets.lookup(speciesControlId) == 1, \"ctrl not retained\");\n    }\n\n    // Transfer a kitty to a new owner\n    function transfer(bytes32 kittyId, pubkey newOwnerPk, signature ownerSig, pubkey ownerPk) {\n        let kittyGroup = tx.assetGroups.find(kittyId);\n\n        // Must be existing kitty (not fresh)\n        require(kittyGroup.isFresh == 0, \"must be existing kitty\");\n\n        // Must be species-controlled\n        require(kittyGroup.control == speciesControlId, \"not species-controlled\");\n\n        // Must be transfer (delta == 0)\n        require(kittyGroup.delta == 0, \"must be transfer only\");\n\n        require(tx.outputs[0].assets.lookup(kittyId) == 1, \"kitty not in output\");\n        require(tx.outputs[0].scriptPubKey == new SingleSig(newOwnerPk), \"wrong destination\");\n        require(checkSig(ownerSig, ownerPk), \"invalid owner sig\");\n    }\n}\n";

export const controlled_mint = "// Controlled Mint Contract\n// Demonstrates asset group introspection primitives\n//\n// This contract manages a token minting authority where:\n// 1. mint() - Authority can mint new tokens (delta > 0), control asset required\n// 2. burn() - Anyone can burn tokens (delta < 0), no control needed\n// 3. lockSupply() - Authority burns the control asset to lock supply forever\n//\n// Asset groups provide aggregate views of asset flows across all inputs/outputs,\n// enabling balance verification without iterating individual UTXOs.\n\noptions {\n  server = server;\n  exit = 288;\n}\n\ncontract ControlledMint(\n  bytes32 tokenAssetId,\n  bytes32 ctrlAssetId,\n  pubkey issuerPk\n) {\n  // Mint: delta > 0, control asset present and retained\n  function mint(int amount, pubkey recipientPk, signature issuerSig) {\n    let tokenGroup = tx.assetGroups.find(tokenAssetId);\n    require(tokenGroup.delta == amount, \"delta mismatch\");\n    require(tokenGroup.control == ctrlAssetId, \"wrong control\");\n\n    let ctrlGroup = tx.assetGroups.find(ctrlAssetId);\n    require(ctrlGroup.delta == 0, \"ctrl supply changed\");\n\n    require(tx.outputs[0].assets.lookup(tokenAssetId) >= amount, \"mint short\");\n    require(tx.outputs[0].scriptPubKey == new SingleSig(recipientPk), \"wrong dest\");\n    require(checkSig(issuerSig, issuerPk), \"bad sig\");\n  }\n\n  // Burn: delta < 0, no control asset needed\n  function burn(int amount, signature ownerSig, pubkey ownerPk) {\n    let tokenGroup = tx.assetGroups.find(tokenAssetId);\n    require(tokenGroup.sumInputs >= tokenGroup.sumOutputs + amount, \"burn short\");\n    require(checkSig(ownerSig, ownerPk), \"bad sig\");\n  }\n\n  // Lock supply forever: burn the control asset\n  function lockSupply(signature issuerSig) {\n    let ctrlGroup = tx.assetGroups.find(ctrlAssetId);\n    require(ctrlGroup.sumOutputs == 0, \"ctrl not burned\");\n    require(checkSig(issuerSig, issuerPk), \"bad sig\");\n  }\n}\n";

export const fee_adapter = "// Fee Adapter Contract\n// Demonstrates arithmetic expressions with tx input/output verification\n//\n// This contract implements a fee-taking adapter where:\n// 1. execute() - Processes a payment, verifying output asset balances\n// 2. The output must preserve assets minus fee\n//\n// Uses asset lookups on tx.inputs and tx.outputs with arithmetic\n// comparisons for balance verification.\n\noptions {\n  server = server;\n  exit = 144;\n}\n\ncontract FeeAdapter(\n  pubkey senderPk,\n  pubkey operatorPk,\n  pubkey recipientPk,\n  bytes32 paymentAssetId,\n  int minFee\n) {\n  // Execute: process payment with fee deduction\n  // Verifies that the output asset balance reflects the fee deduction\n  function execute(signature senderSig, int fee) {\n    // Fee must be at least the minimum\n    require(fee >= minFee, \"fee below minimum\");\n\n    // Input must contain the payment asset\n    require(tx.inputs[0].assets.lookup(paymentAssetId) > 0, \"no payment asset in input\");\n\n    // Output must contain the payment asset (minus fee)\n    require(tx.outputs[0].assets.lookup(paymentAssetId) > 0, \"no payment asset in output\");\n\n    // Sender must sign\n    require(checkSig(senderSig, senderPk), \"invalid sender signature\");\n  }\n\n  // Adjust: operator adjusts fee parameters\n  function adjust(signature operatorSig) {\n    // Operator must sign\n    require(checkSig(operatorSig, operatorPk), \"invalid operator signature\");\n  }\n}\n";

export const fuji_safe = "// Contract configuration options\noptions {\n  // Arkade operator key (always external, never a contract party)\n  server = server;\n  \n  // Exit timelock: 24 hours (144 blocks)\n  exit = 144;\n}\n\n// Fuji Safe Contract\ncontract FujiSafe(\n  // The asset commitment hash (client-side validated)\n  bytes assetCommitmentHash,\n  // The amount being borrowed\n  int borrowAmount,\n  // The borrower's public key\n  pubkey borrowerPk,\n  // The treasury's public key\n  pubkey treasuryPk,\n  // The expiration timeout in blocks\n  int expirationTimeout,\n  // The price level for liquidation\n  int priceLevel,\n  // The setup timestamp\n  int setupTimestamp,\n  // The oracle's public key\n  pubkey oraclePk,\n  // The asset pair identifier\n  bytes assetPair\n) {\n  // Helper function to verify Fuji token burning via Taproot output\n  // Takes the pubkey to use as the internal key for the P2TR output\n  function verifyFujiBurning(pubkey internalKey) internal {\n    // In Taproot, we verify the output is a P2TR that commits to our asset\n    // Using the provided pubkey as the internal key\n    bytes p2trScript = new P2TR(internalKey, assetCommitmentHash);\n    \n    // Verify output 0 has the correct P2TR scriptPubKey and value\n    require(tx.outputs[0].scriptPubKey == p2trScript, \"P2TR output mismatch\");\n    require(tx.outputs[0].value == borrowAmount, \"Value mismatch\");\n  }\n\n  // Claim: Treasury can unlock all collateral after expiration when burning Fuji\n  function claim(signature treasurySig) {\n    // Check that expiration timeout has passed\n    require(tx.time >= expirationTimeout, \"Expiration timeout not reached\");\n    \n    // Verify burning of Fuji token using treasury key\n    verifyFujiBurning(treasuryPk);\n    \n    // Require treasury signature\n    require(checkSig(treasurySig, treasuryPk), \"Invalid treasury signature\");\n  }\n  \n  // Liquidation: Treasury can unlock all collateral with attestation price below the liquidation target\n  function liquidate(int currentPrice, signature oracleSig, signature treasurySig) {\n    // Check price is below liquidation threshold\n    require(currentPrice < priceLevel, \"Price not below liquidation threshold\");\n    \n    // Verify timestamp is after setup\n    require(tx.time >= setupTimestamp, \"Timestamp before setup\");\n    \n    // Create message for oracle signature verification\n    bytes message = sha256(assetPair);\n    \n    // Verify oracle signature on price data\n    require(checkSigFromStack(oracleSig, oraclePk, message), \"Invalid oracle signature\");\n    \n    // Verify burning of Fuji token using treasury key\n    verifyFujiBurning(treasuryPk);\n    \n    // Require treasury signature\n    require(checkSig(treasurySig, treasuryPk), \"Invalid treasury signature\");\n  }\n  \n  // Private Redemption: Only owner can unlock all collateral with key when burning Fuji\n  function redeem(signature borrowerSig) {\n    // Verify burning of Fuji token using borrower key\n    verifyFujiBurning(borrowerPk);\n    \n    // Require borrower signature\n    require(checkSig(borrowerSig, borrowerPk), \"Invalid borrower signature\");\n  }\n  \n  // Treasury Renew: Treasury can unilaterally renew the expiration time\n  function renew(signature treasurySig) {\n    int currentValue = tx.input.current.value;\n\n    // Recreate same contract with identical parameters\n    require(\n      tx.outputs[0].scriptPubKey == new FujiSafe(\n        assetCommitmentHash, borrowAmount, borrowerPk, treasuryPk,\n        expirationTimeout, priceLevel, setupTimestamp, oraclePk, assetPair\n      ),\n      \"contract mismatch\"\n    );\n    require(tx.outputs[0].value == currentValue, \"Value mismatch\");\n\n    // Require treasury signature\n    require(checkSig(treasurySig, treasuryPk), \"Invalid treasury signature\");\n  }\n} ";

export const htlc = "// Contract configuration options\noptions {\n  // Server key \n  server = server;\n  \n  // Renewal timelock: 7 days (1008 blocks)\n  // The contract must be renewed with the Ark server within this period\n  renew = 1008;\n  \n  // Exit timelock: 24 hours (144 blocks)\n  // Time required to exit unilaterally without server involvement\n  exit = 144;\n}\n\ncontract HTLC(\n  pubkey sender,\n  pubkey receiver,\n  bytes hash,\n  int refundTime\n) {\n  // Cooperative close path\n  function together(signature senderSig, signature receiverSig) {\n    require(checkMultisig([sender, receiver], [senderSig, receiverSig]));\n  }\n  \n  // Refund path\n  // This will automatically be compiled into:\n  // 1. Cooperative path: checkSig(sender) && after refundTime && checkSig(server)\n  // 2. Exit path: checkSig(sender) && after refundTime && after 24 hours\n  function refund(signature senderSig) {\n    require(checkSig(senderSig, sender));\n    require(tx.time >= refundTime);\n  }\n  \n  // Claim path\n  // This will automatically be compiled into:\n  // 1. Cooperative path: checkSig(receiver) && sha256(preimage) == hash && checkSig(server)\n  // 2. Exit path: checkSig(receiver) && sha256(preimage) == hash && after 24 hours\n  function claim(signature receiverSig, bytes preimage) {\n    require(checkSig(receiverSig, receiver));\n    require(sha256(preimage) == hash);\n  }\n} ";

export const nft_mint = "// NFT Minting Contract\n// Demonstrates isFresh and assetId properties for unique asset creation\n//\n// This contract enforces:\n// 1. Each NFT is fresh (newly created in this transaction)\n// 2. NFTs are controlled by a collection control asset\n// 3. Only one unit per NFT (delta = 1)\n//\n// Key group properties used:\n// - group.isFresh: Detects if asset was created in current transaction\n// - group.delta: Ensures exactly 1 unit is minted\n// - group.control: Verifies collection membership\n\noptions {\n    server = server;\n    exit = 288;\n}\n\ncontract NFTMint(\n    bytes32 collectionCtrlId,\n    pubkey issuerPk\n) {\n    // Mint a new NFT: must be fresh with delta=1\n    function mint(bytes32 nftAssetId, pubkey recipientPk, signature issuerSig) {\n        let nftGroup = tx.assetGroups.find(nftAssetId);\n\n        // Must be a brand new asset (genesis in this tx)\n        require(nftGroup.isFresh == 1, \"must be fresh\");\n\n        // Must mint exactly 1 (NFT)\n        require(nftGroup.delta == 1, \"must mint exactly 1\");\n\n        // Must be controlled by the collection\n        require(nftGroup.control == collectionCtrlId, \"wrong collection\");\n\n        // Control asset must be retained (delta == 0)\n        let ctrlGroup = tx.assetGroups.find(collectionCtrlId);\n        require(ctrlGroup.delta == 0, \"control must be retained\");\n\n        // NFT goes to recipient\n        require(tx.outputs[0].assets.lookup(nftAssetId) == 1, \"NFT not in output\");\n        require(tx.outputs[0].scriptPubKey == new SingleSig(recipientPk), \"wrong recipient\");\n\n        require(checkSig(issuerSig, issuerPk), \"bad issuer sig\");\n    }\n\n    // Transfer existing NFT (not fresh)\n    function transfer(bytes32 nftAssetId, pubkey newOwnerPk, signature ownerSig, pubkey ownerPk) {\n        let nftGroup = tx.assetGroups.find(nftAssetId);\n\n        // Must NOT be fresh (existing asset)\n        require(nftGroup.isFresh == 0, \"cannot be fresh\");\n\n        // Must be a transfer (delta == 0)\n        require(nftGroup.delta == 0, \"must be transfer\");\n\n        // Must be controlled by the collection\n        require(nftGroup.control == collectionCtrlId, \"wrong collection\");\n\n        // NFT goes to new owner\n        require(tx.outputs[0].assets.lookup(nftAssetId) == 1, \"NFT not in output\");\n        require(tx.outputs[0].scriptPubKey == new SingleSig(newOwnerPk), \"wrong dest\");\n\n        require(checkSig(ownerSig, ownerPk), \"bad owner sig\");\n    }\n\n    // Burn an NFT (delta = -1)\n    function burn(bytes32 nftAssetId, signature ownerSig, pubkey ownerPk) {\n        let nftGroup = tx.assetGroups.find(nftAssetId);\n\n        // Must be existing asset\n        require(nftGroup.isFresh == 0, \"cannot burn fresh asset\");\n\n        // Must burn exactly 1 (negative delta)\n        require(nftGroup.sumInputs >= nftGroup.sumOutputs + 1, \"must burn exactly 1\");\n\n        require(checkSig(ownerSig, ownerPk), \"bad owner sig\");\n    }\n}\n";

export const non_interactive_swap = "// Non-Interactive Swap Contract\n// Allows users to exchange assets without requiring both parties to be online simultaneously.\n//\n// VTXO\n// - Cooperative path: Server emulates/validates introspection, co-signs for fast settlement\n// - Exit path: N-of-N user signatures when introspection is used (pure Bitcoin fallback)\n//\n// Paths:\n// - swap cooperative: takerSig + serverSig + OP_INSPECT* (trustless via introspection)\n// - swap exit: makerSig + takerSig + CSV (N-of-N users, pure Bitcoin)\n// - cancel cooperative: makerSig + serverSig + after(expiration)\n// - cancel exit: makerSig + after(expiration) + CSV (normal exit)\n\noptions {\n  // Server key is injected from getInfo(), not passed in constructor\n  server = server;\n  // Exit delay: 144 blocks (~24 hours) for unilateral recovery\n  exit = 144;\n}\n\ncontract NonInteractiveSwap(\n  // Maker's public key (creator of the swap offer)\n  pubkey makerPk,\n  // Asset ID the maker is offering (locked in this contract)\n  bytes32 offerAssetId,\n  // Amount of offer asset locked\n  int offerAmount,\n  // Asset ID the maker wants to receive\n  bytes32 wantAssetId,\n  // Amount of want asset required for the swap\n  int wantAmount,\n  // Expiration timestamp (block height) after which maker can cancel\n  int expirationTime\n) {\n  // Swap: Any taker can fulfill - introspection makes cooperative path trustless\n  // Cooperative: takerSig + serverSig + OP_INSPECT* (server validates outputs)\n  // Exit: makerSig + takerSig + CSV (N-of-N users, pure Bitcoin - no introspection)\n  function swap(pubkey takerPk, signature takerSig) {\n    // Taker must sign to authorize spending their wantAsset\n    require(checkSig(takerSig, takerPk), \"invalid taker signature\");\n\n    // Introspection verifies the atomic exchange:\n    // Output 0: maker receives wantAsset\n    require(\n      tx.outputs[0].assets.lookup(wantAssetId) >= wantAmount,\n      \"insufficient want asset for maker\"\n    );\n    require(\n      tx.outputs[0].scriptPubKey == new SingleSig(makerPk),\n      \"output 0 not spendable by maker\"\n    );\n\n    // Output 1: taker receives offerAsset\n    require(\n      tx.outputs[1].assets.lookup(offerAssetId) >= offerAmount,\n      \"insufficient offer asset for taker\"\n    );\n    require(\n      tx.outputs[1].scriptPubKey == new SingleSig(takerPk),\n      \"output 1 not spendable by taker\"\n    );\n  }\n\n  // Cancel: Maker reclaims after expiration if no taker\n  // No introspection used, so normal exit path applies\n  // Cooperative: makerSig + serverSig + after(expiration)\n  // Exit: makerSig + after(expiration) + CSV\n  function cancel(signature makerSig) {\n    require(tx.time >= expirationTime, \"swap not expired\");\n    require(checkSig(makerSig, makerPk), \"invalid maker signature\");\n  }\n}\n";

export const payment_auth = "// Payment Authorization Contract\n// Authorization-based escrow with timelocked refunds using transaction introspection\n//\n// This contract implements a credit card-like payment flow:\n// 1. Customer locks funds in escrow\n// 2. Merchant can capture (authorize and settle) the payment\n// 3. If not captured, customer can refund after timelock expires\n//\n// The contract validates the full payout structure:\n// - Merchant receives payment minus processor fee\n// - Processor receives fee (basis points of payment)\n// - Customer receives change if overpayment\n\noptions {\n  server = server;\n  exit = 144;\n}\n\ncontract PaymentAuthorization(\n  // Server key for cooperative path\n  pubkey server,\n\n  // Payment terms\n  int invoiceAmount,\n  int feeRateBasisPoints,\n\n  // Output scripts (P2TR scriptPubKeys)\n  bytes merchantScript,\n  bytes processorScript,\n  bytes customerScript,\n\n  // Refund timelock (block height)\n  int refundBlockHeight,\n\n  // Authorization key\n  pubkey merchantPubkey\n) {\n\n  // Capture: merchant-authorized settlement\n  // Validates payout structure based on payment amount vs invoice\n  function capture(signature merchantSig) {\n    require(checkSig(merchantSig, merchantPubkey), \"Invalid merchant signature\");\n\n    // Get the current input value (amount locked in escrow)\n    let vtxoValue = tx.input.current.value;\n\n    // Case 1: Underpayment (vtxoValue < invoiceAmount)\n    // Pay merchant (minus fee) + processor fee\n    if (vtxoValue < invoiceAmount) {\n      require(vtxoValue >= 10000, \"Payment below dust threshold\");\n      require(tx.numOutputs == 2, \"Expected 2 outputs for underpayment\");\n\n      // Fee = vtxoValue * feeRateBasisPoints / 10000\n      let processorFee = (vtxoValue * feeRateBasisPoints) / 10000;\n      let merchantAmount = vtxoValue - processorFee;\n\n      require(tx.outputs[0].value == merchantAmount, \"Merchant amount incorrect\");\n      require(tx.outputs[0].scriptPubKey == merchantScript, \"Merchant script incorrect\");\n\n      require(tx.outputs[1].value == processorFee, \"Processor fee incorrect\");\n      require(tx.outputs[1].scriptPubKey == processorScript, \"Processor script incorrect\");\n    }\n\n    // Case 2: Exact payment (vtxoValue == invoiceAmount)\n    // Pay merchant (minus fee) + processor fee\n    if (vtxoValue == invoiceAmount) {\n      require(tx.numOutputs == 2, \"Expected 2 outputs for exact payment\");\n\n      // Fee = invoiceAmount * feeRateBasisPoints / 10000\n      let processorFee = (invoiceAmount * feeRateBasisPoints) / 10000;\n      let merchantAmount = invoiceAmount - processorFee;\n\n      require(tx.outputs[0].value == merchantAmount, \"Merchant amount incorrect\");\n      require(tx.outputs[0].scriptPubKey == merchantScript, \"Merchant script incorrect\");\n\n      require(tx.outputs[1].value == processorFee, \"Processor fee incorrect\");\n      require(tx.outputs[1].scriptPubKey == processorScript, \"Processor script incorrect\");\n    }\n\n    // Case 3: Overpayment (vtxoValue > invoiceAmount)\n    // Pay merchant (minus fee) + processor fee + customer change\n    if (vtxoValue > invoiceAmount) {\n      require(tx.numOutputs == 3, \"Expected 3 outputs for overpayment\");\n\n      // Fee = invoiceAmount * feeRateBasisPoints / 10000\n      let processorFee = (invoiceAmount * feeRateBasisPoints) / 10000;\n      let merchantAmount = invoiceAmount - processorFee;\n      let changeAmount = vtxoValue - invoiceAmount;\n\n      require(tx.outputs[0].value == merchantAmount, \"Merchant amount incorrect\");\n      require(tx.outputs[0].scriptPubKey == merchantScript, \"Merchant script incorrect\");\n\n      require(tx.outputs[1].value == processorFee, \"Processor fee incorrect\");\n      require(tx.outputs[1].scriptPubKey == processorScript, \"Processor script incorrect\");\n\n      require(tx.outputs[2].value == changeAmount, \"Change amount incorrect\");\n      require(tx.outputs[2].scriptPubKey == customerScript, \"Change script incorrect\");\n    }\n  }\n\n  // Refund: timelocked fallback back to customer\n  // Becomes valid after refundBlockHeight - effectively anyone-can-spend into customerScript\n  function refund() {\n    require(tx.time >= refundBlockHeight, \"Refund timelock not reached\");\n\n    let vtxoValue = tx.input.current.value;\n\n    require(tx.numOutputs == 1, \"Expected 1 output for refund\");\n    require(tx.outputs[0].value == vtxoValue, \"Refund amount incorrect\");\n    require(tx.outputs[0].scriptPubKey == customerScript, \"Refund script incorrect\");\n  }\n}\n";

export const single_sig = "// Contract configuration options\noptions {\n  // Server key \n  server = server;\n  \n  // Renewal timelock: 7 days (1008 blocks)\n  // The contract must be renewed with the Ark server within this period\n  renew = 1008;\n  \n  // Exit timelock: 24 hours (144 blocks)\n  // Time required to exit unilaterally without server involvement\n  exit = 144;\n}\n\ncontract SingleSig(\n  pubkey user\n) {\n  // Single signature spend path\n  // This will automatically be compiled into:\n  // 1. Cooperative path: checkSig(user) && checkSig(server)\n  // 2. Exit path: checkSig(user) && after 144 blocks\n  function spend(signature userSig) {\n    require(checkSig(userSig, user));\n  }\n} ";

export const threshold_multisig_htlc = "// Contract configuration options\noptions {\n  // Server key \n  server = server;\n  \n  // Renewal timelock: 7 days (1008 blocks)\n  // The contract must be renewed with the Ark server within this period\n  renew = 1008;\n  \n  // Exit timelock: 24 hours (144 blocks)\n  // Time required to exit unilaterally without server involvement\n  exit = 144;\n}\n\ncontract HTLC(\n  pubkey sender,\n  pubkey receiver,\n  bytes hash,\n  int refundTime\n) {\n  // Cooperative close path\n  function together(signature senderSig, signature receiverSig) {\n    require(checkMultisig([sender, receiver]));\n  }\n  \n  // Refund path\n  // This will automatically be compiled into:\n  // 1. Cooperative path: checkSig(sender) && after refundTime && checkSig(server)\n  // 2. Exit path: checkSig(sender) && after refundTime && after 24 hours\n  function refund(signature senderSig) {\n    require(checkSig(senderSig, sender));\n    require(tx.time >= refundTime);\n  }\n  \n  // Claim path\n  // This will automatically be compiled into:\n  // 1. Cooperative path: checkSig(receiver) && sha256(preimage) == hash && checkSig(server)\n  // 2. Exit path: checkSig(receiver) && sha256(preimage) == hash && after 24 hours\n  function claim(signature receiverSig, bytes preimage) {\n    require(checkSig(receiverSig, receiver));\n    require(sha256(preimage) == hash);\n  }\n} ";

export const threshold_oracle = "// Threshold Oracle Contract\n// Generic threshold signature verifier for multi-oracle attestations.\n//\n// This contract demonstrates:\n// - Array types in constructor params (pubkey[] oracles)\n// - Array types in function params (signature[] oracleSigs)\n// - Array indexing (oracles[i])\n// - Loop unrolling with array iteration\n// - Threshold counting for quorum verification\n//\n// N oracles, require M valid signatures over a message.\n\noptions {\n  server = server;\n  exit = 288;\n}\n\ncontract ThresholdOracle(\n  bytes32 tokenAssetId,\n  bytes32 ctrlAssetId,\n  pubkey[] oracles,\n  int threshold\n) {\n  function attest(\n    int amount,\n    bytes32 messageHash,\n    pubkey recipientPk,\n    signature[] oracleSigs\n  ) {\n    require(amount > 0, \"zero\");\n\n    int valid = 0;\n    for (i, sig) in oracleSigs {\n      if (checkSigFromStack(sig, oracles[i], messageHash)) {\n        valid = valid + 1;\n      }\n    }\n    require(valid >= threshold, \"quorum failed\");\n\n    require(tx.inputs[0].assets.lookup(ctrlAssetId) > 0, \"no ctrl\");\n    require(tx.outputs[1].assets.lookup(tokenAssetId) >= amount, \"short\");\n    require(tx.outputs[1].scriptPubKey == new SingleSig(recipientPk), \"wrong dest\");\n    require(tx.outputs[0].scriptPubKey == new ThresholdOracle(tokenAssetId, ctrlAssetId, oracles, threshold), \"broken\");\n  }\n}\n";

export const token_vault = "// Token Vault Contract\n// Demonstrates asset lookup primitives for Arkades Assets\n//\n// This contract locks tokens and allows:\n// 1. deposit() - Owner deposits tokens; output must hold at least as many as input\n// 2. withdraw() - Owner withdraws tokens with server co-signature\n//\n// Asset lookups use the OP_INSPECTINASSETLOOKUP / OP_INSPECTOUTASSETLOOKUP\n// opcodes with sentinel-guard patterns for safe balance verification.\n\noptions {\n  server = server;\n  exit = 144;\n}\n\ncontract TokenVault(\n  pubkey ownerPk,\n  bytes32 tokenAssetId,\n  bytes32 ctrlAssetId\n) {\n  // Deposit: ensure the control asset stays in the output\n  // and output token balance >= input token balance\n  function deposit(signature ownerSig) {\n    // Control asset must be present in input 0\n    require(tx.inputs[0].assets.lookup(ctrlAssetId) > 0, \"no ctrl in input\");\n\n    // Control asset must be present in output 0\n    require(tx.outputs[0].assets.lookup(ctrlAssetId) > 0, \"no ctrl in output\");\n\n    // Output tokens >= input tokens (no leaking tokens)\n    require(\n      tx.outputs[0].assets.lookup(tokenAssetId) >=\n        tx.inputs[0].assets.lookup(tokenAssetId),\n      \"token balance decreased\"\n    );\n\n    // Owner must sign\n    require(checkSig(ownerSig, ownerPk), \"invalid owner signature\");\n  }\n\n  // Withdraw: owner withdraws tokens cooperatively with server\n  function withdraw(signature ownerSig, int amount) {\n    // Control asset must stay in the output\n    require(tx.outputs[0].assets.lookup(ctrlAssetId) > 0, \"no ctrl in output\");\n\n    // Owner must sign\n    require(checkSig(ownerSig, ownerPk), \"invalid owner signature\");\n  }\n}\n";

export const stability_price_beacon = "// PriceBeacon Contract\n//\n// On-chain price oracle. Two values are maintained:\n//   - ticker     (bytes32): identifies the price feed (e.g. commitment to \"BTC/USD\")\n//   - price      (int):     BTC/USD in cents; encoded as the quantity of the ticker asset\n//   - timestamp  (int):     block height of the last update; encoded as quantity of the clock asset\n//\n// Oracle flow:\n//   1. Oracle deploys a PriceBeacon UTXO with an initial price and block height.\n//   2. Oracle calls update() with each new price and the current block height.\n//   3. Settlement contracts read price and timestamp atomically via introspection.\n//   4. Consumers enforce freshness:\n//        int age = tx.time - tx.inputs[N].assets.lookup(clock);\n//        require(age <= 144, \"stale oracle\");  // 144 blocks ≈ 24 hours\n//\n// Security properties:\n//   - Only oraclePk can update price or timestamp.\n//   - Timestamps are monotonically non-decreasing (enforced on-chain).\n//   - Consumers authenticate the beacon by its ticker and clock asset IDs.\n//     Those bytes32 values commit to the oracle's genesis issuance and are\n//     globally unique — the assets cannot be forged. Consumers do NOT bake\n//     oraclePk into their own contracts; oracle key rotation via migrate()\n//     keeps the asset IDs stable, so existing consumers remain valid.\n\noptions {\n  server = server;\n  exit = exit;\n}\n\ncontract PriceBeacon(\n  bytes32 ticker,   // asset whose quantity = BTC/USD price in cents\n  bytes32 clock,    // asset whose quantity = block height of last update\n  pubkey  oraclePk, // authorized updater\n  int     exit      // exit timelock in blocks\n) {\n\n  // -------------------------------------------------------------------------\n  // UPDATE\n  // Oracle publishes a new price and block height.\n  // newBlockHeight must not regress — back-dating across blocks is impossible.\n  // Same-height updates are permitted to support sub-block cadence on Arkade\n  // (the oracle may publish multiple prices within the same Bitcoin block).\n  // -------------------------------------------------------------------------\n  function update(signature oracleSig, int newPrice, int newBlockHeight) {\n    require(checkSig(oracleSig, oraclePk), \"invalid oracle signature\");\n    require(newPrice > 0, \"price must be positive\");\n\n    int currentHeight = tx.inputs[0].assets.lookup(clock);\n    require(newBlockHeight >= currentHeight, \"block height must not regress\");\n\n    require(\n      tx.outputs[0].scriptPubKey == new PriceBeacon(ticker, clock, oraclePk, exit),\n      \"beacon script must survive\"\n    );\n    require(\n      tx.outputs[0].assets.lookup(ticker) == newPrice,\n      \"price not updated correctly\"\n    );\n    require(\n      tx.outputs[0].assets.lookup(clock) == newBlockHeight,\n      \"block height not updated correctly\"\n    );\n  }\n\n  // -------------------------------------------------------------------------\n  // PASSTHROUGH\n  // Any transaction reading the beacon routes it through passthrough.\n  // Both ticker and clock assets must be preserved.\n  // -------------------------------------------------------------------------\n  function passthrough() {\n    require(\n      tx.outputs[0].scriptPubKey == new PriceBeacon(ticker, clock, oraclePk, exit),\n      \"beacon script must survive\"\n    );\n\n    int currentPrice = tx.inputs[0].assets.lookup(ticker);\n    require(\n      tx.outputs[0].assets.lookup(ticker) >= currentPrice,\n      \"price asset must survive\"\n    );\n\n    int currentHeight = tx.inputs[0].assets.lookup(clock);\n    require(\n      tx.outputs[0].assets.lookup(clock) >= currentHeight,\n      \"clock asset must survive\"\n    );\n  }\n\n  // -------------------------------------------------------------------------\n  // MIGRATE\n  // Transfers oracle authority to a new key. Price and block height are preserved.\n  // -------------------------------------------------------------------------\n  function migrate(signature oracleSig, pubkey newOraclePk) {\n    require(checkSig(oracleSig, oraclePk), \"invalid oracle signature\");\n\n    int currentPrice  = tx.inputs[0].assets.lookup(ticker);\n    int currentHeight = tx.inputs[0].assets.lookup(clock);\n\n    require(\n      tx.outputs[0].scriptPubKey == new PriceBeacon(ticker, clock, newOraclePk, exit),\n      \"invalid new beacon\"\n    );\n    require(\n      tx.outputs[0].assets.lookup(ticker) == currentPrice,\n      \"price must be preserved\"\n    );\n    require(\n      tx.outputs[0].assets.lookup(clock) == currentHeight,\n      \"block height must be preserved\"\n    );\n  }\n}\n";

export const stability_stability_offer = "// StabilityOffer Contract\n//\n// Provider pre-commits BTC liquidity into a standing offer.\n// Any swap service (or direct Seeker) can claim it non-interactively,\n// producing a live StabilityVault position.\n//\n// Flow:\n//   1. Provider deploys StabilityOffer with their BTC collateral.\n//   2. Swap service calls take(userBTC, seekerPk) when a user deposits.\n//   3. take() reads the current beacon price, creates a StabilityVault for the user,\n//      and returns a reduced-capacity offer (or nothing if fully consumed).\n//   4. Provider calls withdraw() to reclaim unused collateral at any time.\n//\n// Collateral structure:\n//   Provider collateral = (collateralRatioPct / 100) × seekerBTC\n//   Total vault collateral = seekerBTC + (collateralRatioPct / 100) × seekerBTC\n//   collateralRatioPct = 150 → 1.5:1 ratio, 2.5× total, 60% drop coverage\n//   collateralRatioPct = 200 → 2.0:1 ratio, 3.0× total, 67% drop coverage\n//   Higher ratio = safer for Seeker, lower leverage for Provider.\n//   Minimum enforced at 100 (1:1). Market discovers the equilibrium rate.\n//\n// Funding rate (fundingSatPerBlock):\n//   Positive = Provider pays Seeker per block (cost of self-custodied leverage).\n//   Negative = Seeker pays Provider (discount offer for lower-demand periods).\n//   Set at deployment; market discovers the equilibrium rate.\n\nimport \"stability_vault.ark\";\n\noptions {\n  server = server;\n  exit = exit;\n}\n\ncontract StabilityOffer(\n  pubkey  providerPk,          // offer creator and collateral provider\n  bytes32 ticker,              // PriceBeacon ticker asset: quantity = BTC/USD in cents\n  bytes32 clock,               // PriceBeacon clock asset: quantity = block height\n  int     fundingSatPerBlock,  // signed; positive = provider pays seeker\n  int     maxExposureBTC,      // remaining capacity: max total seekerBTC this offer accepts\n  int     collateralRatioPct,  // provider collateral as % of seekerBTC (e.g. 150 = 1.5:1, min 100)\n  int     exit                 // exit timelock in blocks\n) {\n\n  // -------------------------------------------------------------------------\n  // TAKE\n  // Swap service (or Seeker directly) claims part of this offer.\n  // Reads live BTC/USD price from beacon (input[1]).\n  // Creates a StabilityVault at the current price.\n  // No Provider signature required — offer is pre-committed, fully non-interactive.\n  //\n  // Transaction layout:\n  //   input[0]:  this StabilityOffer UTXO\n  //   input[1]:  PriceBeacon UTXO (pass-through)\n  //   input[2]:  taker's BTC input (userBTC sats for the Seeker side)\n  //   output[0]: StabilityVault ((1 + collateralRatioPct/100)*userBTC collateral)\n  //   output[1]: remaining StabilityOffer (capacity reduced), if any\n  //   output[N]: PriceBeacon pass-through (output[1] if fully consumed, output[2] otherwise)\n  // -------------------------------------------------------------------------\n  function take(int userBTC, pubkey seekerPk) {\n    require(userBTC > 0, \"zero deposit\");\n    require(userBTC <= maxExposureBTC, \"exceeds offer capacity\");\n    require(collateralRatioPct >= 100, \"collateral ratio below minimum\");\n\n    // Authenticate beacon by asset IDs only — ticker and clock commit to\n    // the oracle's genesis issuance and are globally unique.\n    int entryPrice = tx.inputs[1].assets.lookup(ticker);\n    require(entryPrice > 0, \"invalid beacon price\");\n\n    // Enforce freshness (144 blocks ≈ 24 hours)\n    int beaconHeight = tx.inputs[1].assets.lookup(clock);\n    int beaconAge = tx.time - beaconHeight;\n    require(beaconAge <= 144, \"stale oracle\");\n\n    // USD claim for the seeker (in cents)\n    int targetUSD = userBTC * entryPrice / 100000000;\n    require(targetUSD > 0, \"position too small\");\n\n    // Total collateral: seekerBTC + (collateralRatioPct/100)*seekerBTC\n    int totalCollateral = userBTC * (100 + collateralRatioPct) / 100;\n\n    // output[0]: new StabilityVault for the Seeker\n    require(\n      tx.outputs[0].scriptPubKey == new StabilityVault(\n        seekerPk, providerPk, ticker, clock,\n        targetUSD, totalCollateral, fundingSatPerBlock, tx.time, exit\n      ),\n      \"invalid vault output\"\n    );\n    require(tx.outputs[0].value >= totalCollateral, \"insufficient vault collateral\");\n\n    // Beacon index depends on whether output[1] holds the remaining offer\n    int remainingCapacity = maxExposureBTC - userBTC;\n    if (remainingCapacity > 0) {\n      require(\n        tx.outputs[1].scriptPubKey == new StabilityOffer(\n          providerPk, ticker, clock,\n          fundingSatPerBlock, remainingCapacity, collateralRatioPct, exit\n        ),\n        \"invalid remaining offer\"\n      );\n      int remainingCollateral = remainingCapacity * collateralRatioPct / 100;\n      require(tx.outputs[1].value >= remainingCollateral, \"insufficient offer collateral\");\n\n      // Beacon at output[2] when remaining offer present\n      require(\n        tx.outputs[2].assets.lookup(ticker) >= entryPrice,\n        \"beacon must survive\"\n      );\n      require(\n        tx.outputs[2].assets.lookup(clock) >= beaconHeight,\n        \"beacon clock must survive\"\n      );\n    } else {\n      // Fully consumed: no output[1] offer — beacon at output[1]\n      require(\n        tx.outputs[1].assets.lookup(ticker) >= entryPrice,\n        \"beacon must survive\"\n      );\n      require(\n        tx.outputs[1].assets.lookup(clock) >= beaconHeight,\n        \"beacon clock must survive\"\n      );\n    }\n  }\n\n  // -------------------------------------------------------------------------\n  // WITHDRAW\n  // Provider reclaims unclaimed collateral from the offer.\n  // -------------------------------------------------------------------------\n  function withdraw(signature providerSig) {\n    require(checkSig(providerSig, providerPk), \"invalid provider sig\");\n  }\n}\n";

export const stability_stability_vault = "// StabilityVault Contract\n//\n// A USD-denominated claim backed by BTC collateral.\n// Seeker locks BTC and holds a fixed USD value. Provider matches the Seeker's\n// BTC with additional collateral, taking a leveraged BTC long position.\n// Provider pays Seeker a funding rate (fundingSatPerBlock > 0) as the cost\n// of self-custodied leverage.\n//\n// Primary flow: Seeker transfers the position to a swap service in exchange\n// for USDT/USDC. The swap service holds positions as USD inventory float.\n// seekerRedeem and providerExit are settlement valves, not the normal exit path.\n//\n// Collateral structure:\n//   totalCollateral = seekerBTC + (collateralRatioPct/100) × seekerBTC\n//   At collateralRatioPct = 150 (1.5:1): totalCollateral = 2.5 × seekerBTC\n//   Coverage ceiling: 60% price drop from entry\n//   Provider leverage: 1.67×\n//\n// Settlement math:\n//   seekerBase     = targetUSD × 1e8 / currentPrice\n//   fundingAccrued = fundingSatPerBlock × (tx.time - openHeight)\n//   seekerRaw      = seekerBase + fundingAccrued\n//   seekerPayout   = clamp(seekerRaw, 0, totalCollateral)\n//   providerPayout = totalCollateral - seekerPayout\n//\n// Oracle: A PriceBeacon UTXO must be passed as input[1] in all settlement\n// and transfer transactions. The beacon is authenticated by its ticker and\n// clock asset IDs — those `bytes32` values commit to the oracle's genesis\n// issuance transaction and are globally unique. The vault does not need to\n// bake in the oracle's pubkey: oracle key rotation via PriceBeacon.migrate()\n// keeps the asset IDs stable, so existing vaults remain valid. Staleness is\n// enforced at 144 blocks (≈ 24 hours). The ticker asset quantity encodes\n// BTC/USD in cents; the clock asset quantity encodes the last update as a\n// block height.\n//\n// Re-collateralization: if BTC drops beyond the coverage ceiling and the\n// Provider does not call providerExit, the position remains live. When the\n// BTC price recovers, the normal settlement branch is restored automatically —\n// no on-chain action required.\n\nimport \"single_sig.ark\";\n\noptions {\n  server = server;\n  exit = exit;\n}\n\ncontract StabilityVault(\n  pubkey  seekerPk,           // current holder of the USD claim\n  pubkey  providerPk,         // collateral provider, holds the long side\n  bytes32 ticker,             // PriceBeacon ticker asset: quantity = BTC/USD in cents\n  bytes32 clock,              // PriceBeacon clock asset: quantity = block height\n  int     targetUSD,          // seeker's USD claim in cents (immutable across transfers)\n  int     totalCollateral,    // sats locked\n  int     fundingSatPerBlock, // signed: >0 provider pays seeker, <0 seeker pays\n  int     openHeight,         // block height at position open; basis for funding accrual\n  int     exit                // exit timelock in blocks\n) {\n\n  // -------------------------------------------------------------------------\n  // TRANSFER\n  // Seeker assigns the entire position to a new owner, pubkey newSeekerPk.\n  // All economic parameters are preserved. openHeight is unchanged so funding\n  // accrues continuously across transfers.\n  // -------------------------------------------------------------------------\n  function transfer(signature seekerSig, pubkey newSeekerPk) {\n    require(checkSig(seekerSig, seekerPk), \"invalid seeker sig\");\n\n    // Authenticate beacon by asset IDs only — ticker and clock are globally\n    // unique and committed at vault open time.\n    int currentPrice = tx.inputs[1].assets.lookup(ticker);\n    require(currentPrice > 0, \"invalid beacon price\");\n\n    // Enforce freshness (144 blocks ≈ 24 hours)\n    int beaconHeight = tx.inputs[1].assets.lookup(clock);\n    int beaconAge = tx.time - beaconHeight;\n    require(beaconAge <= 144, \"stale oracle\");\n\n    // Position output: identical contract with new seekerPk\n    require(\n      tx.outputs[0].scriptPubKey == new StabilityVault(\n        newSeekerPk, providerPk, ticker, clock,\n        targetUSD, totalCollateral, fundingSatPerBlock, openHeight, exit\n      ),\n      \"invalid transfer output\"\n    );\n    require(tx.outputs[0].value >= totalCollateral, \"collateral not preserved\");\n\n    // Beacon must survive — both assets preserved\n    require(\n      tx.outputs[1].assets.lookup(ticker) >= currentPrice,\n      \"beacon must survive\"\n    );\n    require(\n      tx.outputs[1].assets.lookup(clock) >= beaconHeight,\n      \"beacon clock must survive\"\n    );\n  }\n\n  // -------------------------------------------------------------------------\n  // SPLIT\n  // Seeker divides the USD claim into two independent positions.\n  // amountUSD goes to newSeekerPk; the remainder stays with seekerPk.\n  // Collateral splits proportionally to the USD claim ratio.\n  // openHeight is preserved on both outputs so funding accrues continuously.\n  // -------------------------------------------------------------------------\n  function split(signature seekerSig, int amountUSD, pubkey newSeekerPk) {\n    require(checkSig(seekerSig, seekerPk), \"invalid seeker sig\");\n    require(amountUSD > 0, \"zero amount\");\n    require(amountUSD < targetUSD, \"amount exceeds balance\");\n\n    // Authenticate beacon by asset IDs only.\n    int currentPrice = tx.inputs[1].assets.lookup(ticker);\n    require(currentPrice > 0, \"invalid beacon price\");\n\n    int beaconHeight = tx.inputs[1].assets.lookup(clock);\n    int beaconAge = tx.time - beaconHeight;\n    require(beaconAge <= 144, \"stale oracle\");\n\n    int remainingUSD = targetUSD - amountUSD;\n\n    // Proportional collateral split\n    int collateralA = totalCollateral * amountUSD / targetUSD;\n    int collateralB = totalCollateral - collateralA;\n\n    // Both halves must be above Taproot dust (330 sats)\n    require(collateralA >= 330, \"split amount too small\");\n    require(collateralB >= 330, \"remainder too small\");\n\n    // output[0]: recipient receives amountUSD slice\n    require(\n      tx.outputs[0].scriptPubKey == new StabilityVault(\n        newSeekerPk, providerPk, ticker, clock,\n        amountUSD, collateralA, fundingSatPerBlock, openHeight, exit\n      ),\n      \"invalid split output 0\"\n    );\n    require(tx.outputs[0].value >= collateralA, \"insufficient collateral A\");\n\n    // output[1]: seeker retains remainder\n    require(\n      tx.outputs[1].scriptPubKey == new StabilityVault(\n        seekerPk, providerPk, ticker, clock,\n        remainingUSD, collateralB, fundingSatPerBlock, openHeight, exit\n      ),\n      \"invalid split output 1\"\n    );\n    require(tx.outputs[1].value >= collateralB, \"insufficient collateral B\");\n\n    // output[2]: beacon passthrough\n    require(\n      tx.outputs[2].assets.lookup(ticker) >= currentPrice,\n      \"beacon must survive\"\n    );\n    require(\n      tx.outputs[2].assets.lookup(clock) >= beaconHeight,\n      \"beacon clock must survive\"\n    );\n  }\n\n  // -------------------------------------------------------------------------\n  // SEEKER REDEEM\n  // Seeker exits to BTC at the live oracle price.\n  // seekerPayout = clamp(seekerRaw, 0, totalCollateral)\n  //\n  // Provider re-collateralization: if BTC has dropped beyond the coverage\n  // ceiling and providerExit has not been called, the position stays live.\n  // When BTC recovers, the normal settlement branch is restored automatically.\n  // -------------------------------------------------------------------------\n  function seekerRedeem(signature seekerSig) {\n    require(checkSig(seekerSig, seekerPk), \"invalid seeker sig\");\n\n    // Authenticate beacon by asset IDs only.\n    int currentPrice = tx.inputs[1].assets.lookup(ticker);\n    require(currentPrice > 0, \"invalid beacon price\");\n\n    int beaconHeight = tx.inputs[1].assets.lookup(clock);\n    int beaconAge = tx.time - beaconHeight;\n    require(beaconAge <= 144, \"stale oracle\");\n\n    int blocksElapsed = tx.time - openHeight;\n    int seekerBase    = targetUSD * 100000000 / currentPrice;\n    int funding       = fundingSatPerBlock * blocksElapsed;\n    int seekerRaw     = seekerBase + funding;\n\n    if (seekerRaw <= 0) {\n      // Funding depleted seeker's claim: provider takes everything.\n      require(tx.outputs[0].value >= totalCollateral, \"provider underpaid\");\n      require(\n        tx.outputs[0].scriptPubKey == new SingleSig(providerPk),\n        \"output 0 not provider\"\n      );\n      require(\n        tx.outputs[1].assets.lookup(ticker) >= currentPrice,\n        \"beacon must survive\"\n      );\n      require(\n        tx.outputs[1].assets.lookup(clock) >= beaconHeight,\n        \"beacon clock must survive\"\n      );\n    } else {\n      if (seekerRaw >= totalCollateral) {\n        // Undercollateralised: seeker takes everything, provider gets nothing.\n        require(tx.outputs[0].value >= totalCollateral, \"seeker underpaid\");\n        require(\n          tx.outputs[0].scriptPubKey == new SingleSig(seekerPk),\n          \"output 0 not seeker\"\n        );\n        require(\n          tx.outputs[1].assets.lookup(ticker) >= currentPrice,\n          \"beacon must survive\"\n        );\n        require(\n          tx.outputs[1].assets.lookup(clock) >= beaconHeight,\n          \"beacon clock must survive\"\n        );\n      } else {\n        // Normal settlement: split proportionally\n        require(tx.outputs[0].value >= seekerRaw, \"seeker underpaid\");\n        require(\n          tx.outputs[0].scriptPubKey == new SingleSig(seekerPk),\n          \"output 0 not seeker\"\n        );\n        int providerPayout = totalCollateral - seekerRaw;\n        if (providerPayout > 330) {\n          // Two payout outputs → beacon at output[2]\n          require(tx.outputs[1].value >= providerPayout, \"provider underpaid\");\n          require(\n            tx.outputs[1].scriptPubKey == new SingleSig(providerPk),\n            \"output 1 not provider\"\n          );\n          require(\n            tx.outputs[2].assets.lookup(ticker) >= currentPrice,\n            \"beacon must survive\"\n          );\n          require(\n            tx.outputs[2].assets.lookup(clock) >= beaconHeight,\n            \"beacon clock must survive\"\n          );\n        } else {\n          // Provider payout below Taproot dust: only seeker output → beacon at output[1]\n          require(\n            tx.outputs[1].assets.lookup(ticker) >= currentPrice,\n            \"beacon must survive\"\n          );\n          require(\n            tx.outputs[1].assets.lookup(clock) >= beaconHeight,\n            \"beacon clock must survive\"\n          );\n        }\n      }\n    }\n  }\n\n  // -------------------------------------------------------------------------\n  // PROVIDER EXIT\n  // Provider initiates settlement at the live oracle price.\n  // Economically identical to seekerRedeem — same beacon read, same payout\n  // split. Provider signs instead of Seeker.\n  //\n  // Either party can initiate settlement first; the contract enforces identical\n  // payout math. This is a \"first come, first served\" design — no artificial\n  // delays or precedence.\n  //\n  // The Provider is under no obligation to call this function. If BTC has\n  // dropped beyond the coverage ceiling, the Provider can hold the position\n  // and allow BTC to recover naturally — re-collateralization is automatic\n  // when the price rises back above the coverage threshold.\n  // -------------------------------------------------------------------------\n  function providerExit(signature providerSig) {\n    require(checkSig(providerSig, providerPk), \"invalid provider sig\");\n\n    // Authenticate beacon by asset IDs only.\n    int currentPrice = tx.inputs[1].assets.lookup(ticker);\n    require(currentPrice > 0, \"invalid beacon price\");\n\n    int beaconHeight = tx.inputs[1].assets.lookup(clock);\n    int beaconAge = tx.time - beaconHeight;\n    require(beaconAge <= 144, \"stale oracle\");\n\n    int blocksElapsed = tx.time - openHeight;\n    int seekerBase    = targetUSD * 100000000 / currentPrice;\n    int funding       = fundingSatPerBlock * blocksElapsed;\n    int seekerRaw     = seekerBase + funding;\n\n    if (seekerRaw <= 0) {\n      // Funding depleted seeker's claim: provider takes everything.\n      require(tx.outputs[0].value >= totalCollateral, \"provider underpaid\");\n      require(\n        tx.outputs[0].scriptPubKey == new SingleSig(providerPk),\n        \"output 0 not provider\"\n      );\n      require(\n        tx.outputs[1].assets.lookup(ticker) >= currentPrice,\n        \"beacon must survive\"\n      );\n      require(\n        tx.outputs[1].assets.lookup(clock) >= beaconHeight,\n        \"beacon clock must survive\"\n      );\n    } else {\n      if (seekerRaw >= totalCollateral) {\n        // Undercollateralised: seeker still receives everything.\n        require(tx.outputs[0].value >= totalCollateral, \"seeker underpaid\");\n        require(\n          tx.outputs[0].scriptPubKey == new SingleSig(seekerPk),\n          \"output 0 not seeker\"\n        );\n        require(\n          tx.outputs[1].assets.lookup(ticker) >= currentPrice,\n          \"beacon must survive\"\n        );\n        require(\n          tx.outputs[1].assets.lookup(clock) >= beaconHeight,\n          \"beacon clock must survive\"\n        );\n      } else {\n        require(tx.outputs[0].value >= seekerRaw, \"seeker underpaid\");\n        require(\n          tx.outputs[0].scriptPubKey == new SingleSig(seekerPk),\n          \"output 0 not seeker\"\n        );\n        int providerPayout = totalCollateral - seekerRaw;\n        if (providerPayout > 330) {\n          // Two payout outputs → beacon at output[2]\n          require(tx.outputs[1].value >= providerPayout, \"provider underpaid\");\n          require(\n            tx.outputs[1].scriptPubKey == new SingleSig(providerPk),\n            \"output 1 not provider\"\n          );\n          require(\n            tx.outputs[2].assets.lookup(ticker) >= currentPrice,\n            \"beacon must survive\"\n          );\n          require(\n            tx.outputs[2].assets.lookup(clock) >= beaconHeight,\n            \"beacon clock must survive\"\n          );\n        } else {\n          // Provider payout below Taproot dust: only seeker output → beacon at output[1]\n          require(\n            tx.outputs[1].assets.lookup(ticker) >= currentPrice,\n            \"beacon must survive\"\n          );\n          require(\n            tx.outputs[1].assets.lookup(clock) >= beaconHeight,\n            \"beacon clock must survive\"\n          );\n        }\n      }\n    }\n  }\n}\n";

export const vault_lending_lending_market = "// lending_market.ark\n// Lending market covenant. Manages collateral and debt for one borrower position.\n//\n// Debt is supplied externally via SupplyFlow from VaultCovenant (exogenous path only).\n// Collateral locks in this covenant; borrowed funds flow to the borrower at borrow time.\n//\n// Repayment and liquidation:\n//   repay      — partial or full. Credit holder receives proceeds; full repay releases collateral.\n//   liquidate  — keeper-only. Waterfall: fee to keeper | face value to creditHolder | residual to borrower.\n//   transferCredit — updates creditHolder for secondary market settlement (e.g. NonInteractiveSwap).\n//\n// Division note: all ratio checks use integer arithmetic scaled to basis points.\n// OP_DIV64 floors toward zero. Both sides of the LLTV check are consistently floored,\n// so no systematic bias exists. Ratio boundaries are very slightly borrower-favourable.\n// Liquidation fee truncates down (keeper receives marginally less at fee boundary values).\n//\n// Oracle trust assumption: checkSigFromStack(oracleSig, oraclePk, priceHash) verifies\n// the oracle signed priceHash, but the contract cannot verify that priceHash == hash(price)\n// because the Arkade language has no on-chain hash opcode for this binding. Security relies\n// on the oracle signing a message that commits to a specific price value (e.g. the oracle\n// message format includes the price as a fixed-width field that the verifier checks off-chain).\n// A compromised or colluding caller could replay a stale oracle signature with a different\n// price value. Deployments must ensure the oracle message format is unambiguous and that\n// priceHash commits to a canonical encoding of price.\n\nimport \"lending_market.ark\";\nimport \"single_sig.ark\";\n\noptions {\n  server = server;\n  exit = 144;\n}\n\ncontract LendingMarket(\n  pubkey  borrowerPk,\n  pubkey  oraclePk,\n  pubkey  vaultKeeperPk,\n  bytes32 creditHolder,       // repayment script (RepayFlow scriptPubKey); updated by transferCredit\n  int     collateralAmount,\n  int     debtAmount,\n  int     lltv,               // basis points, e.g. 8500 = 85%\n  bytes32 collateralAssetId,\n  bytes32 loanAssetId,\n  bytes32 oracleHash\n) {\n  // ─── Borrow ───────────────────────────────────────────────────────────────────\n  // Debt was supplied by VaultCovenant via SupplyFlow.\n  // Borrower provides collateral; borrowed funds flow out to borrower on output 1.\n  // Anti-reborrow: borrow() is only valid on a fresh position (debtAmount == 0).\n  // Value conservation: input value (available liquidity) must equal borrowAmount.\n  function borrow(\n    signature borrowerSig,\n    bytes32 priceHash,\n    signature oracleSig,\n    int price,\n    int borrowAmount,\n    int collateral\n  ) {\n    require(checkSig(borrowerSig, borrowerPk), \"invalid borrower\");\n    require(checkSigFromStack(oracleSig, oraclePk, priceHash), \"invalid oracle\");\n\n    // Guard against re-borrowing over an existing position\n    require(debtAmount == 0, \"position already open\");\n    require(collateralAmount == 0, \"position already has collateral\");\n\n    // Value conservation: the market input holds exactly the available liquidity;\n    // borrower must draw the full amount (partial draws leave unaccounted value).\n    require(tx.input.current.value == borrowAmount, \"borrow amount must equal available liquidity\");\n\n    // Collateral ratio check: (collateral * price / 10000) >= (borrowAmount * 10000 / lltv)\n    // Division floors toward zero — see contract header note.\n    int lhs = collateral * price / 10000;\n    int rhs = borrowAmount * 10000 / lltv;\n    require(lhs >= rhs, \"insufficient collateral ratio\");\n\n    // Output 0: updated LendingMarket holding the collateral\n    require(tx.outputs[0].value == collateral, \"collateral must be locked in output 0\");\n    require(\n      tx.outputs[0].scriptPubKey == new LendingMarket(\n        borrowerPk, oraclePk, vaultKeeperPk, creditHolder,\n        collateral, borrowAmount, lltv,\n        collateralAssetId, loanAssetId, oracleHash\n      ),\n      \"successor mismatch\"\n    );\n    // Output 1: borrowed funds flow to borrower\n    require(tx.outputs[1].value == borrowAmount, \"borrower must receive borrow amount\");\n    require(\n      tx.outputs[1].scriptPubKey == new SingleSig(borrowerPk),\n      \"borrower output mismatch\"\n    );\n  }\n\n  // ─── Repay ────────────────────────────────────────────────────────────────────\n  // Borrower repays partial or full debt.\n  // Credit holder receives repayment proceeds on output 1.\n  // Full repay: collateral released to borrower on output 0.\n  // Partial repay: recursive covenant on output 0 with updated debtAmount.\n  function repay(\n    signature borrowerSig,\n    int repayAmount,\n    int newDebtAmount\n  ) {\n    require(checkSig(borrowerSig, borrowerPk), \"invalid borrower\");\n    require(repayAmount > 0, \"repayAmount must be positive\");\n\n    // Verify accounting: newDebtAmount + repayAmount == debtAmount\n    int verifySum = newDebtAmount + repayAmount;\n    require(verifySum == debtAmount, \"invalid repay amounts\");\n\n    // Repayment flows directly to the pre-committed RepayFlow covenant\n    require(tx.outputs[1].value == repayAmount, \"repayment value must match repay amount\");\n    require(tx.outputs[1].scriptPubKey == creditHolder, \"repayment must go to credit script\");\n\n    if (newDebtAmount == 0) {\n      // Full repay: release collateral to borrower\n      require(tx.outputs[0].value == collateralAmount, \"full collateral must be released\");\n      require(\n        tx.outputs[0].scriptPubKey == new SingleSig(borrowerPk),\n        \"collateral must be returned to borrower\"\n      );\n    } else {\n      // Partial repay: recursive covenant with reduced debt; collateral stays locked\n      require(tx.outputs[0].value == collateralAmount, \"partial repay must preserve collateral value\");\n      require(\n        tx.outputs[0].scriptPubKey == new LendingMarket(\n          borrowerPk, oraclePk, vaultKeeperPk, creditHolder,\n          collateralAmount, newDebtAmount, lltv,\n          collateralAssetId, loanAssetId, oracleHash\n        ),\n        \"successor mismatch\"\n      );\n    }\n  }\n\n  // ─── Liquidate ────────────────────────────────────────────────────────────────\n  // Keeper-only. Position must be underwater (threshold < debtAmount).\n  // Liquidation waterfall:\n  //   output 0: liquidation fee (5% of collateral) to keeper\n  //   output 1: face value (debtAmount) to credit holder\n  //   output 2: residual (collateral - fee - debtAmount) to borrower\n  //\n  // Division note: fee = collateralAmount * 500 / 10000 floors toward zero.\n  // residual = collateralAmount - fee - debtAmount (chained subtraction).\n  // Caller is responsible for ensuring collateralAmount >= fee + debtAmount.\n  function liquidate(\n    signature vaultKeeperSig,\n    bytes32 priceHash,\n    signature oracleSig,\n    int price\n  ) {\n    require(checkSig(vaultKeeperSig, vaultKeeperPk), \"invalid keeper\");\n    require(checkSigFromStack(oracleSig, oraclePk, priceHash), \"invalid oracle\");\n\n    // Position is underwater: collateral value * lltv < debt * 10000\n    int ratio = collateralAmount * price / 10000;\n    int threshold = ratio * lltv / 10000;\n    require(threshold < debtAmount, \"position is not underwater\");\n\n    // Liquidation waterfall\n    int fee = collateralAmount * 500 / 10000;\n    int residual = collateralAmount - fee - debtAmount;\n    require(residual >= 0, \"residual must be non-negative\");\n\n    require(tx.outputs[0].value == fee, \"liquidation fee must be exact\");\n    require(\n      tx.outputs[0].scriptPubKey == new SingleSig(vaultKeeperPk),\n      \"fee must go to keeper\"\n    );\n    require(tx.outputs[1].value == debtAmount, \"credit holder payout must be exact\");\n    require(tx.outputs[1].scriptPubKey == creditHolder, \"face value must go to credit script\");\n    require(tx.outputs[2].value >= residual, \"residual to borrower too low\");\n    require(\n      tx.outputs[2].scriptPubKey == new SingleSig(borrowerPk),\n      \"residual must go to borrower\"\n    );\n  }\n\n  // ─── Transfer credit ──────────────────────────────────────────────────────────\n  // Keeper rotates creditHolder to a new RepayFlow script (e.g. to update vault\n  // snapshot after other vault activity before the position is opened).\n  // Only callable on a fresh position (debtAmount == 0) — once a borrower has\n  // drawn against the market the creditHolder is immutable, preventing the keeper\n  // from redirecting repay()/liquidate() proceeds after the fact.\n  function transferCredit(signature keeperSig, bytes32 newHolder) {\n    require(checkSig(keeperSig, vaultKeeperPk), \"invalid keeper\");\n    require(debtAmount == 0, \"cannot rotate credit on open position\");\n    require(\n      tx.outputs[0].scriptPubKey == new LendingMarket(\n        borrowerPk, oraclePk, vaultKeeperPk, newHolder,\n        collateralAmount, debtAmount, lltv,\n        collateralAssetId, loanAssetId, oracleHash\n      ),\n      \"successor mismatch\"\n    );\n    require(tx.outputs[0].value == tx.input.current.value, \"value must be preserved\");\n  }\n}\n";

export const vault_lending_repay_flow = "// repay_flow.ark\n// Inverse of SupplyFlow. Returns repaid assets from a closed LendingMarket back\n// to VaultCovenant, accreting only the interest (yield) earned above principal.\n//\n// Pool accounting: vault.totalAssets stayed FLAT when capital was deployed\n// (SupplyFlow did not decrement it). On return, only interest is added:\n//   interest = returnAmount - supplyAmount\n//   newVaultAssets = totalAssets + interest\n//\n// This preserves the invariant: totalAssets = vault.value + deployedCapital.\n// After repayment, deployedCapital for this loan = 0, vault.value increases by\n// returnAmount, and totalAssets increases by interest only (no double-counting).\n//\n// If returnAmount < supplyAmount (bad debt / partial liquidation), interest < 0\n// and totalAssets decreases — the loss is automatically socialized across all LP\n// shares via share price dilution.\n//\n// creditHolder in LendingMarket is set to the scriptPubKey of this covenant at\n// supply time. Repayment lands here automatically; keeper cannot redirect it.\n//\n// Liveness: reclaim() requires keeper. After the exit timelock (144 blocks),\n// the LP (ownerPk) can call reclaimExpired() unilaterally, supplying current\n// vault state (observable from vault VTXO scriptPubKey on-chain).\n\nimport \"vault_covenant.ark\";\n\noptions {\n  server = server;\n  exit = 144;\n}\n\ncontract RepayFlow(\n  pubkey  vaultKeeperPk,\n  pubkey  ownerPk,\n  bytes32 lpAssetId,\n  int     totalAssets,\n  int     totalShares,\n  int     supplyAmount    // principal deployed; used to isolate interest on return\n) {\n  // ─── Reclaim (cooperative) ────────────────────────────────────────────────────\n  // Keeper routes repaid assets back into VaultCovenant.\n  // Only interest (returnAmount - supplyAmount) is added to totalAssets.\n  function reclaim(signature vaultKeeperSig) {\n    require(checkSig(vaultKeeperSig, vaultKeeperPk), \"invalid vault keeper\");\n\n    int returnAmount = tx.input.current.value;\n    int interest = returnAmount - supplyAmount;\n    int newVaultAssets = totalAssets + interest;\n\n    require(tx.outputs[0].value == returnAmount, \"full value must flow to vault\");\n    require(\n      tx.outputs[0].scriptPubKey == new VaultCovenant(\n        vaultKeeperPk, ownerPk, lpAssetId, newVaultAssets, totalShares\n      ),\n      \"vault successor mismatch\"\n    );\n  }\n\n  // ─── Reclaim expired (unilateral after exit timelock) ─────────────────────────\n  // Available after 144 blocks without keeper action (Ark exit path).\n  // LP supplies current vault totalAssets and totalShares (observable from vault\n  // VTXO scriptPubKey on-chain). Interest is computed the same way as reclaim().\n  function reclaimExpired(signature ownerSig, int currentTotalAssets, int currentTotalShares) {\n    require(checkSig(ownerSig, ownerPk), \"invalid owner\");\n\n    int returnAmount = tx.input.current.value;\n    int interest = returnAmount - supplyAmount;\n    int newVaultAssets = currentTotalAssets + interest;\n\n    require(tx.outputs[0].value == returnAmount, \"full value must flow to vault\");\n    require(\n      tx.outputs[0].scriptPubKey == new VaultCovenant(\n        vaultKeeperPk, ownerPk, lpAssetId, newVaultAssets, currentTotalShares\n      ),\n      \"vault successor mismatch\"\n    );\n  }\n}\n";

export const vault_lending_supply_flow = "// supply_flow.ark\n// One-shot atomic template. Moves BTC from VaultCovenant into a fresh LendingMarket.\n//\n// Pool accounting: vault.totalAssets stays FLAT on capital deployment.\n// Only the vault's physical BTC value (idle capital) decreases; totalAssets continues\n// to count deployed capital. This mirrors Morpho's accounting model: LP share price\n// does not decrease when capital is deployed to a healthy loan.\n//\n// creditHolder must be supplied by the caller as the precomputed scriptPubKey of:\n//   RepayFlow(vaultKeeperPk, ownerPk, lpAssetId, totalAssets, totalShares, supplyAmount)\n// supplyAmount is baked into RepayFlow so interest accounting is correct on return:\n//   interest = returnAmount - supplyAmount; vault.totalAssets += interest only.\n//\n// Value split: vault output receives inputVal - supplyAmount; market output receives supplyAmount.\n\nimport \"vault_covenant.ark\";\nimport \"lending_market.ark\";\n\noptions {\n  server = server;\n  exit = 144;\n}\n\ncontract SupplyFlow(\n  pubkey  vaultKeeperPk,\n  pubkey  ownerPk,\n  pubkey  borrowerPk,\n  pubkey  oraclePk,\n  bytes32 lpAssetId,\n  bytes32 creditHolder,       // scriptPubKey of RepayFlow(vaultKeeperPk, ownerPk, lpAssetId, totalAssets, totalShares, supplyAmount)\n  int     supplyAmount,\n  int     lltv,\n  int     totalAssets,\n  int     totalShares,\n  bytes32 collateralAssetId,\n  bytes32 loanAssetId,\n  bytes32 oracleHash\n) {\n  function supply(signature vaultKeeperSig) {\n    require(checkSig(vaultKeeperSig, vaultKeeperPk), \"invalid vault keeper\");\n    require(supplyAmount <= totalAssets, \"supply amount exceeds vault assets\");\n\n    int inputVal = tx.input.current.value;\n    int vaultOut = inputVal - supplyAmount;\n\n    // Output 0: VaultCovenant with same totalAssets (deployed capital still counted)\n    require(tx.outputs[0].value == vaultOut, \"vault output value mismatch\");\n    require(\n      tx.outputs[0].scriptPubKey == new VaultCovenant(\n        vaultKeeperPk, ownerPk, lpAssetId, totalAssets, totalShares\n      ),\n      \"vault successor mismatch\"\n    );\n\n    // Output 1: fresh LendingMarket seeded with supplyAmount, ready for borrower\n    require(tx.outputs[1].value == supplyAmount, \"market output value mismatch\");\n    require(\n      tx.outputs[1].scriptPubKey == new LendingMarket(\n        borrowerPk, oraclePk, vaultKeeperPk, creditHolder,\n        0, 0, lltv,\n        collateralAssetId, loanAssetId, oracleHash\n      ),\n      \"market successor mismatch\"\n    );\n  }\n}\n";

export const vault_lending_vault_covenant = "// vault_covenant.ark\n// Recursive ERC-4626-style vault. Tracks share accounting and price-per-share (PPS).\n// Only reportYield() can increase totalAssets relative to totalShares.\n// PPS is monotonically non-decreasing: reportYield enforces newTotalAssets >= totalAssets.\n//\n// LP shares are issued as Arkade Assets (lpAssetId) on deposit and burned on withdrawal.\n// This makes LP positions transferable: an LP can sell their shares on a secondary market\n// without touching the vault covenant, providing exit liquidity even at full utilization.\n//\n// Deposit: LP tokens minted to caller (output[1]) proportional to sharesIssued.\n// Withdraw: LP tokens burned from caller (input[1]) proportional to sharesBurned.\n//   Authentication on withdraw is the LP token burn — no ownerSig required.\n//\n// totalAssets invariant: totalAssets = vault.value + deployedCapital.\n// SupplyFlow does NOT decrement totalAssets on capital deployment; RepayFlow\n// accretes only interest (returnAmount - supplyAmount) when capital returns.\n//\n// Division note: all arithmetic uses OP_DIV64 (floor toward zero).\n// PPS ratios are computed off-chain; the covenant enforces state transitions only.\n\nimport \"vault_covenant.ark\";\n\noptions {\n  server = server;\n  exit = 144;\n}\n\ncontract VaultCovenant(\n  pubkey  keeperPk,\n  pubkey  ownerPk,\n  bytes32 lpAssetId,   // Arkade Asset ID for LP share tokens\n  int     totalAssets,\n  int     totalShares\n) {\n  // Deposit: LP provides BTC; LP tokens minted to output[1].\n  // ownerSig gates deposits — keeper controls who can enter the pool.\n  function deposit(signature ownerSig, int newTotalAssets, int newTotalShares) {\n    require(checkSig(ownerSig, ownerPk), \"invalid owner\");\n    require(newTotalShares > totalShares, \"shares must increase\");\n    require(newTotalAssets > totalAssets, \"assets must increase\");\n\n    // Mint LP tokens to the depositor (output[1])\n    int sharesIssued = newTotalShares - totalShares;\n    require(\n      tx.outputs[1].assets.lookup(lpAssetId) == sharesIssued,\n      \"LP tokens must be minted to depositor\"\n    );\n\n    require(\n      tx.outputs[0].scriptPubKey == new VaultCovenant(\n        keeperPk, ownerPk, lpAssetId, newTotalAssets, newTotalShares\n      ),\n      \"successor mismatch\"\n    );\n  }\n\n  // Withdraw: LP burns their LP tokens (input[1]); vault releases proportional BTC.\n  // LP token burn is the authentication — no separate signature required.\n  // Withdrawal is bounded by the vault's idle BTC (vault UTXO value).\n  function withdraw(int newTotalAssets, int newTotalShares) {\n    require(newTotalShares < totalShares, \"shares must decrease\");\n    require(newTotalAssets < totalAssets, \"assets must decrease\");\n\n    // Burn LP tokens from the LP's input (input[1])\n    int sharesBurned = totalShares - newTotalShares;\n    require(\n      tx.inputs[1].assets.lookup(lpAssetId) == sharesBurned,\n      \"LP tokens must be burned\"\n    );\n\n    require(\n      tx.outputs[0].scriptPubKey == new VaultCovenant(\n        keeperPk, ownerPk, lpAssetId, newTotalAssets, newTotalShares\n      ),\n      \"successor mismatch\"\n    );\n  }\n\n  // Only path that can increase PPS.\n  // keeperSig over reportHash prevents intra-block replay.\n  function reportYield(\n    signature keeperSig,\n    bytes32 reportHash,\n    int newTotalAssets\n  ) {\n    require(newTotalAssets >= totalAssets, \"PPS decrease forbidden\");\n    require(checkSigFromStack(keeperSig, keeperPk, reportHash), \"invalid keeper\");\n    require(\n      tx.outputs[0].scriptPubKey == new VaultCovenant(\n        keeperPk, ownerPk, lpAssetId, newTotalAssets, totalShares\n      ),\n      \"successor mismatch\"\n    );\n  }\n}\n";

